INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c4fbcf36-e8f5-467e-bd97-d644a834805e', $q$Scheduling and auto-posting$q$, $q$Built-in publishing suite with approval workflows and auto-posting to connected accounts.$q$, 5);
