INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6807ab40-552b-4044-8610-c58acf04855d', $q$Is PrestaShop free?$q$, $q$The Classic core platform is free and open source to download and self-host; PrestaShop Hosted and Enterprise are paid managed options.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6807ab40-552b-4044-8610-c58acf04855d', $q$What is PrestaShop Hosted?$q$, $q$A managed edition that bundles hosting, installation, and support for merchants who don't want to run their own servers, starting around 24 to 29 dollars per month.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6807ab40-552b-4044-8610-c58acf04855d', $q$Does PrestaShop charge transaction fees?$q$, $q$No, the self-hosted core does not charge a percentage fee on sales; costs come from hosting, modules, and optional paid services.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6807ab40-552b-4044-8610-c58acf04855d', $q$What technology is PrestaShop built on?$q$, $q$PrestaShop is built with PHP and the Symfony framework.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6807ab40-552b-4044-8610-c58acf04855d', $q$Can I migrate from Shopify or WooCommerce to PrestaShop?$q$, $q$Yes, migration is common and supported by third-party tools and PrestaShop's certified agency partners.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6807ab40-552b-4044-8610-c58acf04855d', $q$How many stores use PrestaShop?$q$, $q$PrestaShop reports more than 250,000 active online stores and over a million community members worldwide.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6807ab40-552b-4044-8610-c58acf04855d', $q$Does PrestaShop support multiple languages and currencies?$q$, $q$Yes, multi-language and multi-currency support are built into the core platform.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6807ab40-552b-4044-8610-c58acf04855d', $q$Self-hosted store for developers and agencies$q$, $q$Full control over code, hosting, and customization for teams comfortable managing their own infrastructure.$q$, $q$Developers and web agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6807ab40-552b-4044-8610-c58acf04855d', $q$Managed hosted store for non-technical merchants$q$, $q$PrestaShop Hosted removes server management while retaining most customization options.$q$, $q$Small and mid-sized merchants$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6807ab40-552b-4044-8610-c58acf04855d', $q$Enterprise retail deployment$q$, $q$Large retailers use PrestaShop Enterprise for dedicated infrastructure and deep customization at scale.$q$, $q$Large ecommerce retailers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6807ab40-552b-4044-8610-c58acf04855d', $q$Classic (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full open-source platform","Self-hosted","Access to free modules and themes","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6807ab40-552b-4044-8610-c58acf04855d', $q$Hosted$q$, $q$From $24-29/month$q$, $q$Monthly or annual$q$, NULL, $q$["50GB managed hosting","Store installation included","VAT and GDPR compliance tools","Email/phone support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6807ab40-552b-4044-8610-c58acf04855d', $q$Enterprise$q$, $q$Custom (contact sales)$q$, $q$Annual, minimum term applies$q$, NULL, $q$["Dedicated infrastructure","Account management","Enterprise-grade support","Custom SLAs"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6807ab40-552b-4044-8610-c58acf04855d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$PrestaShop is a free, open-source ecommerce platform that has powered online stores since 2007, giving merchants a self-hosted option built on PHP and Symfony. Because the core software is open source, store owners keep full control over their code, data, and hosting environment rather than depending on a single SaaS vendor for uptime and pricing decisions.$q$, $q$Founded in Paris and still headquartered there as PrestaShop SA, the company has built a large ecosystem around the core platform: a marketplace of paid modules and themes, a network of certified agency partners, and a managed hosting product for merchants who want the openness of PrestaShop without running their own servers. The platform reports more than 250,000 active stores and a community of over a million members globally.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6807ab40-552b-4044-8610-c58acf04855d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At its core, PrestaShop provides catalog management, multi-store and multi-language support, built-in SEO controls, and integrations with major payment and shipping providers, all customizable through PHP-based modules and themes. Merchants who need capabilities beyond the free core can add paid modules from the Addons Marketplace covering areas like checkout optimization, marketing automation, shipping rules, and social commerce.$q$, $q$Compliance tooling for VAT calculation and GDPR/cookie consent is built into both the Classic and Hosted editions, and the platform includes tools for scaling a single install across multiple stores or currencies. For merchants who prefer not to manage servers, PrestaShop Hosted bundles installation, hosting, and support so the technical maintenance burden shifts to PrestaShop while the merchant retains most of the customization options of the open-source edition.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6807ab40-552b-4044-8610-c58acf04855d', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The PrestaShop Classic edition is free to download and self-host indefinitely, with merchants paying only for their own hosting infrastructure and any paid modules or themes they choose from the Addons Marketplace. PrestaShop Hosted, the managed option, starts at roughly 24 dollars per month billed annually, about 29 dollars per month with no commitment, and includes 50GB of hosting, store installation, and compliance tooling.$q$, $q$Larger retailers can move to a custom-priced PrestaShop Enterprise edition, which industry pricing guides estimate can start in the low thousands of dollars per month with a minimum contract term, reflecting dedicated infrastructure, account management, and enterprise-grade support. Across all tiers, the total cost of running a PrestaShop store also depends heavily on which paid modules, themes, and agency services a merchant chooses to add.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6807ab40-552b-4044-8610-c58acf04855d', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
