INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fdeba438-b86f-4bcf-8da7-e3ebc19236f8', $q$Is Pretalx free?$q$, $q$Self-hosting Pretalx is free since it is open source; the hosted version at pretalx.com is priced based on expected event size.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fdeba438-b86f-4bcf-8da7-e3ebc19236f8', $q$What is Pretalx used for?$q$, $q$Managing a conference's Call for Papers, speaker review, communication, and schedule publishing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fdeba438-b86f-4bcf-8da7-e3ebc19236f8', $q$Does Pretalx handle ticketing or payments?$q$, $q$No, Pretalx focuses on the speaker program; organizers typically pair it with a separate ticketing tool like Pretix for registration and payment.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fdeba438-b86f-4bcf-8da7-e3ebc19236f8', $q$How much does hosted Pretalx cost?$q$, $q$Pricing scales with expected attendee count and ticket price, starting around 60 euros for the smallest events, with discounts for non-profit community events.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fdeba438-b86f-4bcf-8da7-e3ebc19236f8', $q$Who maintains Pretalx?$q$, $q$The project is maintained primarily by Tobias Kunze, who also runs the hosted service at pretalx.com.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fdeba438-b86f-4bcf-8da7-e3ebc19236f8', $q$Can I self-host Pretalx?$q$, $q$Yes, the full codebase is open source and available on GitHub for self-hosting.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fdeba438-b86f-4bcf-8da7-e3ebc19236f8', $q$Does Pretalx support multi-track conferences?$q$, $q$Yes, it supports both single-track events and large multi-room, multi-track conferences.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fdeba438-b86f-4bcf-8da7-e3ebc19236f8', $q$Is Pretalx related to Pretix?$q$, $q$They are separate products built by related members of the German open-source events community; Pretalx handles the speaker program while Pretix handles ticketing.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fdeba438-b86f-4bcf-8da7-e3ebc19236f8', $q$Running a conference Call for Papers$q$, $q$Organizers open a customized submission form and manage incoming talk proposals.$q$, $q$Conference program committees$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fdeba438-b86f-4bcf-8da7-e3ebc19236f8', $q$Managing peer review for talk submissions$q$, $q$Review committees score and discuss submissions using anonymous or open review workflows.$q$, $q$Conference organizers and reviewers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fdeba438-b86f-4bcf-8da7-e3ebc19236f8', $q$Publishing and updating a multi-track schedule$q$, $q$Automatically build and maintain a live schedule as sessions are finalized or changed.$q$, $q$Event organizers and speakers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fdeba438-b86f-4bcf-8da7-e3ebc19236f8', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full open-source codebase","Unlimited events and attendees","Plugin ecosystem","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fdeba438-b86f-4bcf-8da7-e3ebc19236f8', $q$Hosted (pretalx.com)$q$, $q$From about EUR 60, scales with attendees and ticket price$q$, $q$Per event$q$, NULL, $q$["Managed hosting and backups","Automatic updates and certificates","Customer support","Up to 25% discount for community events"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fdeba438-b86f-4bcf-8da7-e3ebc19236f8', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Pretalx is open-source software purpose-built to run a conference's speaker program from start to finish: opening a Call for Papers, reviewing and selecting submissions, communicating with speakers, and publishing the final schedule. It is especially popular in the Python and broader open-source conference community, where organizers value transparent, self-hostable tooling over closed commercial platforms.$q$, $q$The project is maintained primarily by Tobias Kunze, who also operates the hosted version of the service at pretalx.com. Because the underlying code is open source, any organizer with the technical resources can self-host Pretalx at no license cost, while those who prefer a managed setup can use the hosted service and pay based on event size.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fdeba438-b86f-4bcf-8da7-e3ebc19236f8', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Pretalx lets organizers build a fully custom Call for Papers form, then route submissions through configurable review workflows that can be anonymous or open, with flexible scoring and selection criteria suited to single-track meetups or large multi-room conferences alike. Built-in email tooling helps organizers communicate with speakers at each stage, including proofreading and editing before messages go out in bulk.$q$, $q$Once talks are selected, Pretalx's scheduling tools automatically build a conference schedule and notify speakers and attendees of any changes. A plugin ecosystem allows the platform to be extended for specific needs, and because the codebase is open source, technical teams can inspect, modify, or self-host it entirely rather than depending on a closed vendor.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fdeba438-b86f-4bcf-8da7-e3ebc19236f8', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Pretalx is free to self-host indefinitely since it is released as open-source software; organizers only pay for their own server and maintenance time. For the hosted service at pretalx.com, pricing is not a flat monthly fee but is calculated based on expected attendee numbers and standard ticket price, so cost scales with the size of the event.$q$, $q$The smallest community events can run a Call for Papers on the hosted platform for roughly 60 euros, and non-profit, volunteer-run community events can qualify for a discount of up to 25 percent. Organizers can explore and configure the hosted platform for free and only pay once they make their event public, and events with unusual revenue models can contact the team directly to arrange custom pricing.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fdeba438-b86f-4bcf-8da7-e3ebc19236f8', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
