INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('283e6deb-e069-4af7-88a7-a176d867da95', $q$Is Pretix free?$q$, $q$Self-hosting is free since it is open source; the hosted service charges a percentage fee only on paid tickets sold.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('283e6deb-e069-4af7-88a7-a176d867da95', $q$How much does Pretix charge per ticket?$q$, $q$2.5 percent of the ticket price, capped at 15 euros per ticket, plus payment-provider fees; free tickets are fee-free for the first 500 per year.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('283e6deb-e069-4af7-88a7-a176d867da95', $q$Can I self-host Pretix?$q$, $q$Yes, the full codebase is open source under Apache 2.0 and can be self-hosted at no license cost.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('283e6deb-e069-4af7-88a7-a176d867da95', $q$Is Pretix the same as Pretalx?$q$, $q$No, they are separate products from the same broader German open-source events community; Pretix handles ticketing and Pretalx handles Call for Papers and scheduling.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('283e6deb-e069-4af7-88a7-a176d867da95', $q$Does Pretix support free events?$q$, $q$Yes, free tickets are fee-free for the first 500 issued per year on the hosted plan.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('283e6deb-e069-4af7-88a7-a176d867da95', $q$What payment providers does Pretix support?$q$, $q$Stripe, PayPal, Mollie, and other integrated payment providers.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('283e6deb-e069-4af7-88a7-a176d867da95', $q$Does Pretix have a check-in app?$q$, $q$Yes, a companion app handles ticket scanning and entry management at the door.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('283e6deb-e069-4af7-88a7-a176d867da95', $q$Who is behind Pretix?$q$, $q$Pretix was founded by Raphael Michel and is operated by pretix GmbH in Heidelberg, Germany.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('283e6deb-e069-4af7-88a7-a176d867da95', $q$Selling tickets for a conference or festival$q$, $q$Organizers configure multiple ticket tiers, accept payments, and manage entry at the door.$q$, $q$Event organizers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('283e6deb-e069-4af7-88a7-a176d867da95', $q$Free registration for community meetups$q$, $q$Community groups use the free-ticket allowance to manage RSVPs without transaction fees.$q$, $q$Community and meetup organizers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('283e6deb-e069-4af7-88a7-a176d867da95', $q$Self-hosted ticketing for privacy-conscious organizations$q$, $q$Technical teams run Pretix on their own infrastructure to keep full control of attendee data.$q$, $q$Enterprises and privacy-focused event teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('283e6deb-e069-4af7-88a7-a176d867da95', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full open-source codebase","Unlimited events and tickets","Public API and plugin support","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('283e6deb-e069-4af7-88a7-a176d867da95', $q$Hosted (pretix.eu)$q$, $q$2.5% of ticket price (max EUR 15/ticket) for paid tickets; first 500 free tickets/year at no charge$q$, $q$Per ticket sold, no monthly fee$q$, NULL, $q$["No monthly subscription","Unlimited users","Email and phone support","No minimum contract term"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('283e6deb-e069-4af7-88a7-a176d867da95', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Pretix is an open-source ticketing and event registration platform founded in 2014 by Raphael Michel in Heidelberg, Germany. It focuses squarely on the commercial and logistical side of running an event: selling tickets, collecting payments, issuing invoices, and managing entry, rather than the speaker-program or content-review side that a tool like Pretalx handles.$q$, $q$Because the full codebase is open source, organizations can self-host Pretix for free with complete control over their data, or use the hosted pretix.eu service and pay only when tickets are actually sold. This dual model has made it popular with both privacy-conscious European organizations and community event organizers who want to avoid flat SaaS subscription fees.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('283e6deb-e069-4af7-88a7-a176d867da95', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Pretix supports configurable ticket types and pricing tiers, checkout integrated with multiple payment providers, automated invoicing, waiting lists, voucher and discount codes, and optional seating charts for venues that need assigned seating. A companion check-in app handles entry scanning at the door, and an exhibitor lead-scanning module is available as a paid add-on for trade shows and conferences.$q$, $q$Because it is open source with a public API, technical teams can extend Pretix with custom plugins or integrate it directly into their own registration workflows. The platform is designed to be GDPR-friendly and restricts service to business entities rather than individual consumers, positioning it firmly as B2B event infrastructure.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('283e6deb-e069-4af7-88a7-a176d867da95', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Pretix charges no flat monthly subscription on its hosted plan. Instead, paid tickets are charged 2.5 percent of the ticket price excluding tax, capped at 15 euros per ticket, plus whatever fees the chosen payment provider charges; free tickets incur no charge for the first 500 issued per year, with a small fee of 0.50 euros per ticket after that allowance is used.$q$, $q$Optional add-on modules are billed separately, including roughly 25 euros per exhibitor for lead scanning and 0.20 euros per invoice for Peppol or regional e-invoicing compliance. Organizations that prefer to avoid transaction fees entirely, or that need full control over their data, can instead self-host the open-source Pretix codebase at no license cost, paying only for their own infrastructure.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('283e6deb-e069-4af7-88a7-a176d867da95', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
