INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('99ec53f2-7bec-4016-a54d-dea91440a5b5', $q$Is Principle free?$q$, $q$No, it offers a 14-day free trial and then requires a one-time purchase of 129 dollars.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('99ec53f2-7bec-4016-a54d-dea91440a5b5', $q$Is Principle available for Windows?$q$, $q$No, Principle is Mac-only, though shared prototypes can be viewed and interacted with in a browser on any operating system.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('99ec53f2-7bec-4016-a54d-dea91440a5b5', $q$Does Principle integrate with Figma?$q$, $q$Yes, designs can be imported from Figma, and re-importing after edits intelligently merges changes.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('99ec53f2-7bec-4016-a54d-dea91440a5b5', $q$Can I export video from Principle?$q$, $q$Yes, finished animations can be exported as video files or animated GIFs.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('99ec53f2-7bec-4016-a54d-dea91440a5b5', $q$Who made Principle?$q$, $q$Principle was created by Daniel Hooper, a former Apple engineer, and launched in 2015.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('99ec53f2-7bec-4016-a54d-dea91440a5b5', $q$Does Principle support Apple Silicon Macs?$q$, $q$Yes, it runs natively on both Intel and Apple Silicon Macs.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('99ec53f2-7bec-4016-a54d-dea91440a5b5', $q$Is there a subscription option for Principle?$q$, $q$No, Principle is sold only as a one-time perpetual license that includes one year of free updates.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('99ec53f2-7bec-4016-a54d-dea91440a5b5', $q$How is Principle different from Figma's prototyping features?$q$, $q$Principle offers deeper, frame-by-frame timeline control over animation compared to Figma's built-in Smart Animate.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('99ec53f2-7bec-4016-a54d-dea91440a5b5', $q$Prototyping mobile app micro-interactions$q$, $q$Designers fine-tune transitions and gestures to match the intended feel of a native app.$q$, $q$UI and UX designers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('99ec53f2-7bec-4016-a54d-dea91440a5b5', $q$Creating motion demos for stakeholder review$q$, $q$Teams share interactive, web-based prototypes to get feedback before development begins.$q$, $q$Product designers and agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('99ec53f2-7bec-4016-a54d-dea91440a5b5', $q$Producing animated portfolio pieces$q$, $q$Designers export polished video or GIF demos of interface concepts for portfolios and case studies.$q$, $q$Designers and design educators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('99ec53f2-7bec-4016-a54d-dea91440a5b5', $q$Principle License$q$, $q$$129$q$, $q$One-time (perpetual license, includes 1 year of updates)$q$, NULL, $q$["Full timeline-based animation editor","Figma and Sketch import","One-click web sharing","Video and GIF export","14-day free trial before purchase"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('99ec53f2-7bec-4016-a54d-dea91440a5b5', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Principle is a macOS design application focused entirely on interaction and animation: rather than being a general-purpose design tool, it takes static artboards and turns them into believable, interactive prototypes with realistic motion. It was created in 2015 by Daniel Hooper, a former Apple engineer, who built the app independently from Atlanta, Georgia before growing a small team around it.$q$, $q$The app has become a go-to tool for designers who need to demonstrate exactly how a screen transition, gesture, or micro-interaction should feel, something static mockup tools and even many prototyping tools struggle to convey. Its Mac-only, timeline-based approach has earned it a loyal following among UI and UX designers at companies ranging from startups to Apple, Google, and Netflix.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('99ec53f2-7bec-4016-a54d-dea91440a5b5', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Principle's core is a visual timeline that gives frame-by-frame control over easing, timing, and sequencing, letting designers fine-tune bounces, transitions, and gestures without writing animation code. Designs can be imported directly from Figma or Sketch, and re-importing after edits intelligently merges changes rather than forcing a rebuild from scratch, which keeps the design and prototyping workflow tightly connected.$q$, $q$Beyond animation, Principle supports multi-screen flows viewed from a bird's-eye perspective, device presets for mobile, web, and desktop artboards, and live preview on a connected iOS device for testing gestures on real hardware. Finished prototypes can be shared to the web with a single click, viewable by anyone in a browser regardless of their operating system, or exported as a video or animated GIF for decks and portfolios.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('99ec53f2-7bec-4016-a54d-dea91440a5b5', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Unlike most modern design tools, Principle is not a subscription product. It is sold as a one-time perpetual license for 129 dollars, which includes one year of free updates from the date of purchase, and the developer offers a 14-day free trial so designers can evaluate the full app before buying.$q$, $q$There is no separate free tier and no lower-priced starter plan; the single license unlocks the entire feature set. Team usage is supported through the purchase of additional seats rather than a dedicated team-pricing plan, keeping Principle's pricing structure notably simpler than most competing prototyping tools.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2273c295-f582-4fee-a5d0-42845b0dfade', $q$Cookieless tracking$q$, $q$Tracks visitors without cookies or personal data, avoiding the need for a cookie-consent banner.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2273c295-f582-4fee-a5d0-42845b0dfade', $q$Real-time data processing$q$, $q$Traffic and event data appear on dashboards immediately rather than after a reporting delay.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2273c295-f582-4fee-a5d0-42845b0dfade', $q$Custom events and dashboards$q$, $q$Track specific goals and build tailored visualization panels beyond basic pageviews.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2273c295-f582-4fee-a5d0-42845b0dfade', $q$Bot and scraper filtering$q$, $q$Automatically filters out bot, scraper, and spam traffic to show genuine visitor numbers.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2273c295-f582-4fee-a5d0-42845b0dfade', $q$SQL query API$q$, $q$Query raw analytics data directly for advanced, custom analysis.$q$, 4);
