INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2273c295-f582-4fee-a5d0-42845b0dfade', $q$Unlimited data retention$q$, $q$Visitor data is never automatically deleted, preserving full historical trends.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2273c295-f582-4fee-a5d0-42845b0dfade', $q$Self-hostable open source$q$, $q$Full codebase available under AGPL-3.0, built on ClickHouse and Grafana, for self-hosting.$q$, 7);
