INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2273c295-f582-4fee-a5d0-42845b0dfade', $q$Is Prisme Analytics free?$q$, $q$The self-hosted open-source version is free; the hosted cloud version is a paid service priced around 8.99 euros per month.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2273c295-f582-4fee-a5d0-42845b0dfade', $q$Does Prisme Analytics use cookies?$q$, $q$No, it is a cookieless analytics tool that does not collect personal data.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2273c295-f582-4fee-a5d0-42845b0dfade', $q$Is Prisme Analytics GDPR compliant?$q$, $q$Yes, it is designed to be compliant with GDPR, PECR, and Schrems II without requiring a cookie-consent banner.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2273c295-f582-4fee-a5d0-42845b0dfade', $q$What is Prisme Analytics built on?$q$, $q$It is built on ClickHouse for data storage and Grafana for dashboarding.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2273c295-f582-4fee-a5d0-42845b0dfade', $q$How much does hosted Prisme Analytics cost?$q$, $q$Around 8.99 euros per month for a single all-inclusive plan covering unlimited websites, pageviews, events, and dashboards.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2273c295-f582-4fee-a5d0-42845b0dfade', $q$Can I self-host Prisme Analytics?$q$, $q$Yes, the full codebase is open source under AGPL-3.0 and available on GitHub.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2273c295-f582-4fee-a5d0-42845b0dfade', $q$Does Prisme Analytics offer a free trial?$q$, $q$Yes, the hosted cloud service offers a 30-day free trial with no credit card required.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2273c295-f582-4fee-a5d0-42845b0dfade', $q$How is Prisme different from Google Analytics?$q$, $q$Prisme is cookieless, processes data in real time, does not sell or share visitor data, and offers a fully open-source self-hosting option.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2273c295-f582-4fee-a5d0-42845b0dfade', $q$Privacy-compliant analytics without cookie banners$q$, $q$Website owners track traffic while staying compliant with privacy regulations, without showing a cookie banner.$q$, $q$Website owners and bloggers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2273c295-f582-4fee-a5d0-42845b0dfade', $q$Self-hosted analytics for technical teams$q$, $q$Developers run Prisme on their own infrastructure for full control over analytics data.$q$, $q$Developers and technical teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2273c295-f582-4fee-a5d0-42845b0dfade', $q$Real-time traffic monitoring for content and ecommerce sites$q$, $q$Teams monitor live traffic and conversion events without waiting for delayed reporting.$q$, $q$Content creators and ecommerce businesses$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2273c295-f582-4fee-a5d0-42845b0dfade', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full open-source codebase (AGPL-3.0)","Unlimited websites and events","SQL query API","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2273c295-f582-4fee-a5d0-42845b0dfade', $q$Cloud Hosted$q$, $q$EUR 8.99/month$q$, $q$Monthly$q$, NULL, $q$["Unlimited websites and pageviews","Unlimited events and dashboards","Real-time reporting","30-day free trial, no credit card required"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2273c295-f582-4fee-a5d0-42845b0dfade', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Prisme Analytics is an open-source web analytics platform designed as a cookieless alternative to Google Analytics. Built by the small, EU-based team at Prisme Labs, it is released under the AGPL-3.0 open-source license and built on ClickHouse for data storage and Grafana for visualization, giving it a real-time reporting experience rather than the delayed reporting typical of larger analytics platforms.$q$, $q$Because Prisme does not use cookies or collect personal data, sites using it can typically skip a cookie-consent banner for analytics purposes while remaining compliant with GDPR, PECR, and Schrems II. It is offered both as free, self-hosted software and as a low-cost hosted cloud service, appealing to privacy-conscious website owners and technical teams alike.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2273c295-f582-4fee-a5d0-42845b0dfade', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Prisme processes visitor data in real time, so traffic and event data appear on dashboards immediately rather than after a reporting delay. Built-in bot and scraper filtering keeps reported numbers focused on genuine human visits, while custom events and custom dashboards let teams track specific conversion goals or user actions beyond basic pageviews.$q$, $q$For teams that want raw access to their data, a SQL query API allows direct querying beyond the built-in dashboards. The tracking script itself is lightweight to minimize any performance or SEO impact, and a no-JavaScript pixel-tag option is available for situations where a full script cannot be used. Since the platform is open source, self-hosting teams can also inspect or modify the underlying ClickHouse and Grafana-based infrastructure.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2273c295-f582-4fee-a5d0-42845b0dfade', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Because Prisme Analytics is open source under AGPL-3.0, any team can self-host the full platform for free, paying only for their own server infrastructure. This makes it a genuinely no-cost option for technical teams comfortable running ClickHouse and Grafana themselves.$q$, $q$For teams that prefer a managed service, Prisme's hosted cloud plan is a single, all-inclusive tier priced around 8.99 euros per month, covering unlimited websites, pageviews, events, and dashboards rather than splitting features across multiple pricing tiers. A 30-day free trial with no credit card required lets prospective customers evaluate the hosted service before committing.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2273c295-f582-4fee-a5d0-42845b0dfade', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
