INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9e4d2898-7923-44d2-a2aa-f2138ec31ce4', $q$Is Prismic free?$q$, $q$Yes, Prismic offers a limited free plan with 1 user, 4 million API calls per month, and 2 locales.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9e4d2898-7923-44d2-a2aa-f2138ec31ce4', $q$What is Slice Machine?$q$, $q$A developer tool for defining reusable page sections, called slices, in code, which marketers then assemble visually into pages.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9e4d2898-7923-44d2-a2aa-f2138ec31ce4', $q$Is Prismic a headless CMS?$q$, $q$Yes, it is API-first and delivers content via REST and GraphQL to any front-end framework.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9e4d2898-7923-44d2-a2aa-f2138ec31ce4', $q$Does Prismic support multiple languages?$q$, $q$Yes, locale support is included on every plan, with the number of locales increasing on higher tiers.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9e4d2898-7923-44d2-a2aa-f2138ec31ce4', $q$How is Prismic priced?$q$, $q$Per content repository, per month, billed annually, across Free, Starter, Small, Medium, Platinum, and custom Enterprise tiers.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9e4d2898-7923-44d2-a2aa-f2138ec31ce4', $q$Does Prismic work with Next.js?$q$, $q$Yes, as an API-first headless CMS it integrates with Next.js and other modern front-end frameworks.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9e4d2898-7923-44d2-a2aa-f2138ec31ce4', $q$Does Prismic offer AI features?$q$, $q$Yes, including AI-assisted translation and direct integration with AI assistants like ChatGPT and Claude via the Model Context Protocol.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9e4d2898-7923-44d2-a2aa-f2138ec31ce4', $q$Who founded Prismic?$q$, $q$Prismic was founded in 2013 by a team of seven developers working at a digital agency in Paris.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9e4d2898-7923-44d2-a2aa-f2138ec31ce4', $q$Scaling marketing landing pages without dev bottlenecks$q$, $q$Marketers assemble pages from developer-built slices to ship campaigns quickly.$q$, $q$Marketing teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9e4d2898-7923-44d2-a2aa-f2138ec31ce4', $q$Powering a headless website front-end$q$, $q$Developers use Prismic's content API to power a site built in Next.js, Nuxt, or another framework.$q$, $q$Developers and engineering teams$q$, 1);
