INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9e4d2898-7923-44d2-a2aa-f2138ec31ce4', $q$Free$q$, $q$$0/month$q$, $q$Per repository, annual$q$, NULL, $q$["1 user","4 million API calls/month","100GB CDN bandwidth","2 locales","Visual Page Builder"]$q$::jsonb, 0);
