INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9e4d2898-7923-44d2-a2aa-f2138ec31ce4', $q$Small$q$, $q$$25/month$q$, $q$Per repository, billed annually$q$, NULL, $q$["7 users","4 locales","Everything in Starter"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9e4d2898-7923-44d2-a2aa-f2138ec31ce4', $q$Medium$q$, $q$$150/month$q$, $q$Per repository, billed annually$q$, NULL, $q$["25 users","5 locales","User roles","Everything in Small"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9e4d2898-7923-44d2-a2aa-f2138ec31ce4', $q$Platinum$q$, $q$$675/month$q$, $q$Per repository, billed annually$q$, NULL, $q$["Unlimited users","8 locales","Development environment","Everything in Medium"]$q$::jsonb, 4);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9e4d2898-7923-44d2-a2aa-f2138ec31ce4', $q$Enterprise$q$, $q$Custom (contact sales)$q$, $q$Annual, custom$q$, NULL, $q$["Custom usage quotas","SSO","Dedicated customer success manager","Uptime SLAs"]$q$::jsonb, 5);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9e4d2898-7923-44d2-a2aa-f2138ec31ce4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Prismic is a headless content management system founded in Paris in 2013 by a team of seven developers who wanted a better way to manage web content while working at a digital agency. The company has since grown into a dedicated CMS vendor with staff across more than 20 nationalities, still headquartered in Paris, and has raised a 20 million dollar Series A round led by Accel.$q$, $q$Rather than shipping a fixed page-building system, Prismic centers its product around Slice Machine, which lets developers define reusable, brand-approved page components in code that marketers can then freely assemble into pages through a visual builder. This split of responsibilities is meant to give marketing teams speed and editing freedom while keeping design and code quality under developer control.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9e4d2898-7923-44d2-a2aa-f2138ec31ce4', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Slice Machine is Prismic's signature feature: developers build a library of reusable slices, such as heroes, testimonials, or pricing tables, and marketers combine, reorder, and edit those slices on any page without breaking the underlying design or needing a developer for routine content updates. Content is delivered through both REST and GraphQL content APIs, so it can power any front-end framework, including Next.js, Nuxt, and Astro.$q$, $q$Prismic also supports multilingual and multi-locale content management, AI-assisted translation, and SEO and GEO landing-page optimization tools with schema markup support. More recent additions include an ABM landing-page builder for account-based marketing campaigns and direct integration with AI assistants like ChatGPT and Claude through the Model Context Protocol, letting teams generate or edit content using AI tooling connected directly to their Prismic repository.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9e4d2898-7923-44d2-a2aa-f2138ec31ce4', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Prismic prices its plans per content repository, billed annually, with each tier increasing the number of users, locales, API call limits, and CDN bandwidth included. The Free plan covers 1 user, 4 million API calls per month, 100GB of CDN bandwidth, and 2 locales; Starter is 10 dollars per month for 3 users and 3 locales; Small is 25 dollars per month for 7 users and 4 locales; Medium is 150 dollars per month for 25 users, 5 locales, and user roles; and Platinum is 675 dollars per month for unlimited users, 8 locales, and development environments.$q$, $q$Organizations with more demanding requirements can move to a custom-priced Enterprise tier that adds SSO, a dedicated customer success manager, priority support, infosec and legal review, and uptime SLAs. Because pricing is per repository, teams running multiple brands or sites on separate repositories should factor in that each one is billed independently.$q$]::text[], 2);
