-- ── Prefect ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Prefect is a Python-native workflow orchestration platform for building, scheduling, and monitoring data and AI pipelines, available as an open-source engine or as the managed Prefect Cloud.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (open source or Hobby cloud tier); paid plans from $100/month (Starter)$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$Washington, D.C., United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Prefect Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Prefect review: Python workflow orchestration platform. See open-source vs Prefect Cloud pricing, key features, and comparisons to Airflow and Dagster.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Prefect is a Python-native workflow orchestration platform founded in 2018 by Jeremiah Lowin and headquartered in Washington, D.C., built by Prefect Technologies, Inc. Engineers define data, ML, and agentic pipelines as plain Python functions decorated with flow and task decorators, and Prefect's engine handles scheduling, automatic retries, state tracking, caching, and crash recovery without requiring a proprietary DSL or a self-managed scheduler like Apache Airflow's. The open-source core, licensed under Apache 2.0 with roughly 50,000 GitHub stars, can be self-hosted for free with unlimited workflows; Prefect Cloud is the company's managed control plane that adds a hosted UI, serverless compute through work pools, enterprise SSO and SCIM, audit logs, and role-based access control on top of the same open-source engine, so teams can run workloads in their own infrastructure while Prefect hosts only the orchestration layer. Pricing follows a freemium, usage-based model: a free Hobby tier with 2 users, 1 workspace, 5 deployments, and 500 serverless credit-minutes per month; a Starter plan at roughly 100 dollars per month with 3 seats, 20 deployments, and 4,500 serverless minutes; a Team plan at roughly 400 dollars per month with up to 8 seats, 50 deployments, 13,500 serverless minutes, service accounts, and audit logs; and a custom-priced Enterprise tier with unlimited seats and deployments, SSO and SAML, granular RBAC, and an uptime SLA above 99.9 percent. Prefect targets data engineers, ML and AI engineering teams, and platform teams running production pipelines, with disclosed users including Cash App, Ramp, WHOOP, Meta, NASA, and Cisco. Its main differentiator versus Apache Airflow is a lighter-weight, more Pythonic developer experience with dynamic, code-first workflows rather than static DAG files, plus first-class support for hybrid execution where code and data never leave the customer's own infrastructure. Against newer entrants such as Dagster, which emphasizes asset-centric orchestration, and general-purpose durable-execution engines like Temporal or Argo Workflows, Prefect positions itself as the more approachable, Python-first option for data and ML teams. The competitors most often cited alongside Prefect include Apache Airflow, Dagster, Temporal, and Argo Workflows.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '2d51e95d-ce2a-4513-a287-44c9039f1a17';

