-- ── Pretalx ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Pretalx is an open-source conference management system for handling Call for Papers, speaker review, and scheduling, usable free as self-hosted software or as a paid hosted service at pretalx.com.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted); hosted pricing on pretalx.com scales with event size, from about EUR 60 for the smallest events$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE($q$Not publicly disclosed (small, maintainer-led team)$q$, company_size),
  headquarters = COALESCE($q$Germany (exact office location not publicly disclosed)$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$]::text[],
  seo_title = COALESCE($q$Pretalx Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Pretalx review: open-source Call for Papers and conference scheduling tool. See features, hosted pricing, self-hosting, and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Pretalx is an open-source conference management system built primarily by Tobias Kunze, who also runs the hosted service at pretalx.com, and is maintained as free, open-source software. It covers the full lifecycle of a conference's speaker program: opening and customizing a Call for Papers, collecting and either anonymously or openly peer-reviewing talk submissions, managing speaker communication and email templates, and automatically building and publishing the event schedule with change notifications. The software is widely used across the Python, open-source, and academic or tech conference circuit, including editions of events like PyCon and DjangoCon, largely because organizers can self-host it for free on their own servers with no per-attendee fee, or extend it through a plugin ecosystem for needs like video integration or badge workflows. For organizers who prefer not to run their own server, the maintainers operate a hosted SaaS version at pretalx.com; pricing there is not a flat subscription but scales with expected attendee count and standard ticket price, with the smallest community events able to run a Call for Papers for roughly 60 euros, and non-profit, volunteer-run community events eligible for a discount of up to 25 percent, while larger or commercial conferences pay proportionally more. Testing and internal use of the hosted platform before making an event public is free of charge. Pretalx's core differentiator is its narrow, deep focus on the Call-for-Papers-to-schedule workflow for single- or multi-track conferences, rather than being a general event-ticketing or registration platform; it explicitly complements ticketing tools rather than replacing them and is commonly deployed alongside a separate ticketing system such as Pretix, built by a related German open-source developer community, which handles registration and payment. Target users are conference organizers, program committees, and volunteer-run tech communities that need transparent, configurable peer review and scheduling without vendor lock-in. Competitors and alternatives include OpenReview and EasyChair for academic paper review, and tools such as Sessionize and Papercall.io on the broader conference-platform side, which similarly manage speaker submissions and schedules for conferences and meetups.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'fdeba438-b86f-4bcf-8da7-e3ebc19236f8';

