-- ── Pretix ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Pretix is an open-source event ticketing and registration platform from Germany that handles ticket sales, checkout, invoicing, and entry management, available self-hosted for free or as a hosted SaaS billed per ticket.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted, or first 500 free tickets/year on hosted); paid tickets on hosted plan cost 2.5% of ticket price up to EUR 15/ticket$q$, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE($q$Not publicly disclosed (small team)$q$, company_size),
  headquarters = COALESCE($q$Heidelberg, Germany$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$]::text[],
  seo_title = COALESCE($q$Pretix Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Pretix review: open-source event ticketing platform. See per-ticket pricing, self-hosting option, key features, and how it differs from Pretalx.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Pretix is an open-source event ticketing and registration platform founded in 2014 by Raphael Michel and operated by pretix GmbH, headquartered in Heidelberg, Germany. It handles the commercial side of running an event: configurable ticket types and pricing tiers, checkout with multiple payment providers including Stripe, PayPal, and Mollie, automated invoicing, waiting lists, voucher and discount codes, seating charts, and check-in or entry scanning through a companion app, plus an exhibitor lead-scanning add-on. The codebase is fully open source under the Apache 2.0 license and can be self-hosted for free with no license fee, which appeals to organizations that need full data control or want to avoid per-ticket fees at scale. Alternatively, the hosted SaaS version at pretix.eu charges no monthly fee and instead uses a pay-as-you-sell model: 2.5 percent of the ticket price, capped at 15 euros per ticket, for paid tickets plus payment-provider fees, while free tickets carry no charge for the first 500 issued per year and a small fee thereafter, with add-on modules like lead scanning or e-invoicing priced separately. Pretix targets event organizers ranging from small community meetups to large commercial conferences, festivals, and trade shows that need reliable, GDPR-compliant ticketing infrastructure with predictable, transaction-based pricing rather than flat subscription tiers. Its main differentiator versus SaaS incumbents like Eventbrite or Tito is the open-source, self-hostable core combined with lower per-ticket fees, no forced platform branding, and deep customization through plugins and a public API. It is frequently used alongside, and sometimes confused with, Pretalx, a separate but related open-source tool from the same broader German open-source events community that handles Call for Papers and conference program scheduling rather than ticket sales; organizers running an academic or tech conference often pair Pretix for registration and payment with Pretalx for the speaker program. Other competitors include Eventbrite, Tito, and Ticket Tailor for commercial ticketing.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '283e6deb-e069-4af7-88a7-a176d867da95';

